# non-vacuous assertions.

import ast
import re
import subprocess
from pathlib import Path

import pytest

AC_UID = "0a4adefb36fd614e"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
TARGET_DIR = REPO_ROOT / "tests" / "generated" / "20260520-221452"
EXPECTED_COUNT = 13

FORBIDDEN_PATTERNS = [
    re.compile(r"^    pass$", re.MULTILINE),
    re.compile(r"TEST_INCOMPLETE:"),
    re.compile(r"\bassert True\b"),
    re.compile(r"\bassert 1\s*==\s*1\b"),
    re.compile(r"pytest\.skip\b"),
    re.compile(r"@pytest\.mark\.skip\b"),
]


def _collect_files():
    return sorted(TARGET_DIR.glob("test_AC_*.py"))


def test_AC_01():
    """
    GIVEN: All 13 tests/generated/20260520-221452/test_AC_*.py files exist (live Glob count must equal 13)
    WHEN:  Each file is read AND pytest tests/generated/20260520-221452/ -q is run
    THEN:  Zero files contain bare 'pass' as sole body; zero contain 'TEST_INCOMPLETE:' sentinel; zero contain vacuous assertions; zero use pytest.skip or @pytest.mark.skip; each test body references the target file/path/symbol named in its docstring GIVEN clause; each test body contains at least one assertion exercising the THEN clause specific predicate
    """
    files = _collect_files()
    assert len(files) == EXPECTED_COUNT, (
        f"Expected {EXPECTED_COUNT} test_AC_*.py files under {TARGET_DIR}, "
        f"found {len(files)}: {[f.name for f in files]}"
    )

    violations = []

    for f in files:
        src = f.read_text(encoding="utf-8")

        # 1) Forbidden patterns
        for pat in FORBIDDEN_PATTERNS:
            if pat.search(src):
                violations.append(f"{f.name}: forbidden pattern {pat.pattern!r}")

        # 2) AST: at least one assert statement, and not a constant True
        tree = ast.parse(src)
        asserts = [n for n in ast.walk(tree) if isinstance(n, ast.Assert)]
        if not asserts:
            violations.append(f"{f.name}: contains zero assert statements")
        else:
            non_constant = [
                a for a in asserts
                if not (isinstance(a.test, ast.Constant) and bool(a.test.value) is True)
            ]
            if not non_constant:
                violations.append(f"{f.name}: every assert is a constant-true")

        # 3) Body must not be just `pass`. Find the test_ function and check.
        for node in ast.walk(tree):
            if isinstance(node, ast.FunctionDef) and node.name.startswith("test_"):
                non_doc = [
                    n for n in node.body
                    if not (isinstance(n, ast.Expr) and isinstance(n.value, ast.Constant) and isinstance(n.value.value, str))
                ]
                if len(non_doc) == 1 and isinstance(non_doc[0], ast.Pass):
                    violations.append(f"{f.name}: function {node.name} has only pass body")

        # 4) Each test references the target named in its docstring GIVEN clause
        docstrings = re.findall(r'GIVEN:\s*(.+)', src)
        if not docstrings:
            violations.append(f"{f.name}: missing GIVEN docstring")
        else:
            given = docstrings[0]
            # extract candidate path/symbol tokens (file paths, dotted names)
            tokens = re.findall(r'[A-Za-z0-9_./\-]+\.(?:py|md|json|sh|yaml|yml|toml)', given)
            tokens += re.findall(r'[a-zA-Z_][a-zA-Z0-9_]{3,}', given)
            # Only require referencing if there is a clear filename token
            file_tokens = [t for t in tokens if "." in t and "/" in t]
            if file_tokens:
                if not any(tok in src for tok in file_tokens) and not any(
                    Path(tok).name in src for tok in file_tokens
                ):
                    violations.append(
                        f"{f.name}: body does not reference any GIVEN target {file_tokens}"
                    )

    assert not violations, (
        "Cycle 2 skeletons still unrealized — "
        + str(len(violations))
        + " violations:\n  - "
        + "\n  - ".join(violations)
    )

    # 5) Runtime: pytest collection succeeds and zero tests are skipped via pytest.skip
    result = subprocess.run(
        ["python3", "-m", "pytest", str(TARGET_DIR), "--collect-only", "-q"],
        capture_output=True,
        text=True,
        cwd=str(REPO_ROOT),
        timeout=60,
    )
    # Collection must succeed (rc 0 or 5=no-tests is unacceptable)
    assert result.returncode == 0, (
        f"pytest --collect-only failed rc={result.returncode}\n"
        f"stdout:\n{result.stdout}\nstderr:\n{result.stderr}"
    )
